  box-sizing: border-box;
}

body {
  margin: 0;
  min-width: 320px;
  min-height: 100vh;
}

button,
input,
textarea {
  font: inherit;
}

button {
  border: 0;
  border-radius: 999px;
  background: #2357d9;
  color: #fff;
  cursor: pointer;
  font-weight: 700;
  padding: 0.85rem 1.2rem;
  transition: transform 160ms ease, box-shadow 160ms ease, background 160ms ease;
  box-shadow: 0 12px 30px rgba(35, 87, 217, 0.22);
}

button:hover:not(:disabled),
button:focus-visible:not(:disabled) {
  background: #1746b7;
  transform: translateY(-1px);
}

button:disabled {
  cursor: not-allowed;
  opacity: 0.55;
}

button.secondary {
  background: #fff;
  color: #23314d;
  box-shadow: inset 0 0 0 1px rgba(35, 49, 77, 0.16);
}

input,
textarea {
  width: 100%;
  border: 1px solid #c6d0df;
  border-radius: 16px;
  color: #172033;
  background: #fff;
  margin-top: 0.45rem;
  padding: 0.85rem 1rem;
}

input:focus,
textarea:focus,
button:focus-visible {
  outline: 3px solid rgba(35, 87, 217, 0.28);
  outline-offset: 2px;
}

textarea {
  min-height: 7rem;
  resize: vertical;
}

.app-shell {
  min-height: 100vh;
  padding: 2rem;
}

.topbar {
  align-items: center;
  display: flex;
  justify-content: space-between;
  margin: 0 auto 1.5rem;
  max-width: 1080px;
}

.topbar > div {
  align-items: center;
  display: flex;
  gap: 0.75rem;
}

.brand-mark {
  align-items: center;
  background: #172033;
  border-radius: 14px;
  color: #fff;
  display: inline-flex;
  font-weight: 800;
  height: 2.5rem;
  justify-content: center;
  letter-spacing: -0.08em;
  width: 2.5rem;
