  box-shadow: 0 24px 80px rgba(23, 32, 51, 0.12);
  margin: 0 auto;
  max-width: 1080px;
  padding: 2rem;
}

.auth-card {
  max-width: 520px;
}

.stack {
  display: grid;
  gap: 1rem;
  margin-top: 1.5rem;
}

.eyebrow {
  color: #2357d9;
  font-size: 0.78rem;
  font-weight: 800;
  letter-spacing: 0.12em;
  margin: 0 0 0.5rem;
  text-transform: uppercase;
}

h1,
h2,
p {
  margin-top: 0;
}

h1 {
  font-size: clamp(2rem, 5vw, 3.6rem);
  letter-spacing: -0.05em;
  line-height: 0.95;
  margin-bottom: 1rem;
}

h2 {
  font-size: 1.2rem;
  margin-bottom: 0.35rem;
}

.muted {
  color: #5b677c;
  line-height: 1.6;
}

.banner {
  margin-bottom: 1rem;
  padding: 1rem 1.25rem;
}

.banner p {
